import { motion, useMotionValue, useTransform } from 'framer-motion';
import { FiArrowRight, FiPlay } from 'react-icons/fi';
import { FaBrain } from 'react-icons/fa';

const Hero = () => {
  const x = useMotionValue(0);
  const y = useMotionValue(0);
  const rotateX = useTransform(y, [-100, 100], [15, -15]);
  const rotateY = useTransform(x, [-100, 100], [-15, 15]);

  const handleMouseMove = (e) => {
    const rect = e.currentTarget.getBoundingClientRect();
    x.set(e.clientX - rect.left - rect.width / 2);
    y.set(e.clientY - rect.top - rect.height / 2);
  };

  return (
    <section className="relative overflow-hidden bg-gradient-to-br from-gray-900 via-purple-900 to-gray-900 py-24 md:py-32">
      {/* Floating neural dots */}
      <div className="absolute inset-0 overflow-hidden opacity-20">
        {[...Array(50)].map((_, i) => (
          <motion.div
            key={`dot-${i}`}
            className="absolute rounded-full bg-purple-500"
            style={{
              width: `${Math.random() * 6 + 2}px`,
              height: `${Math.random() * 6 + 2}px`,
              left: `${Math.random() * 100}%`,
              top: `${Math.random() * 100}%`,
            }}
            animate={{
              x: [0, (Math.random() - 0.5) * 50],
              y: [0, (Math.random() - 0.5) * 50],
              opacity: [0.2, 0.8, 0.2],
            }}
            transition={{
              duration: 10 + Math.random() * 20,
              repeat: Infinity,
            }}
          />
        ))}
      </div>

      <div className="relative max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 grid lg:grid-cols-2 gap-16 items-center">
        {/* Text Content */}
        <div className="text-center lg:text-left">
          <motion.h1
            className="text-4xl md:text-5xl lg:text-6xl font-bold text-white mb-6 leading-tight"
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ duration: 0.6 }}
          >
            <span className="block">Next-Generation</span>
            <span className="bg-gradient-to-r from-purple-400 to-cyan-400 bg-clip-text text-transparent">
              AI Detection
            </span>
          </motion.h1>

          <motion.p
            className="text-lg md:text-xl text-gray-300 mb-10 max-w-lg mx-auto lg:mx-0"
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            transition={{ delay: 0.4, duration: 0.6 }}
          >
            Our neural networks analyze content with unprecedented accuracy, identifying AI-generated patterns in real-time.
          </motion.p>

          <motion.div 
            className="flex flex-col sm:flex-row gap-4 justify-center lg:justify-start"
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            transition={{ delay: 0.8 }}
          >
            <motion.a
              href="#demo"
              className="flex items-center justify-center gap-3 bg-gradient-to-r from-purple-600 to-blue-500 text-white px-6 py-3 rounded-xl font-medium shadow-lg hover:shadow-xl transition-all group"
              whileHover={{ scale: 1.05 }}
              whileTap={{ scale: 0.98 }}
            >
              Experience Demo
              <FiArrowRight className="ml-1 group-hover:translate-x-1 transition-transform" />
            </motion.a>

            <motion.a
              href="#technology"
              className="flex items-center justify-center gap-3 text-white px-6 py-3 rounded-xl font-medium border border-white/20 hover:bg-white/10 transition-colors group"
              whileHover={{ y: -2 }}
            >
              <FiPlay className="text-purple-400 group-hover:text-purple-300" />
              How It Works
            </motion.a>
          </motion.div>
        </div>

        {/* 3D AI Neural Network Visualization */}
        <motion.div 
          className="relative h-80 md:h-96 lg:h-[500px]"
          onMouseMove={handleMouseMove}
          style={{
            perspective: 1000,
            rotateX,
            rotateY,
          }}
        >
          <div className="absolute inset-0 rounded-3xl overflow-hidden border border-white/10 bg-gradient-to-br from-purple-900/30 to-blue-900/20 backdrop-blur-sm flex items-center justify-center">
            {/* Neural Network Core */}
            <div className="relative w-full h-full">
              {/* Central AI Processor */}
              <motion.div
                className="absolute top-1/2 left-1/2 transform -translate-x-1/2 -translate-y-1/2 z-10"
                animate={{
                  scale: [1, 1.05, 1],
                  rotate: [0, 5, 0]
                }}
                transition={{
                  duration: 8,
                  repeat: Infinity,
                  repeatType: "mirror"
                }}
              >
                <div className="p-4 bg-gradient-to-br from-purple-500/20 to-blue-400/20 rounded-full border border-white/10 shadow-2xl">
                  <div className="p-6 bg-gradient-to-br from-purple-600 to-blue-500 rounded-full flex items-center justify-center text-white shadow-inner">
                    <FaBrain className="h-12 w-12" />
                  </div>
                </div>
              </motion.div>

              {/* Neural Layers & Connections */}
              <svg className="absolute inset-0 h-full w-full" xmlns="http://www.w3.org/2000/svg">
                <defs>
                  <linearGradient id="gradient" x1="0%" y1="0%" x2="100%" y2="100%">
                    <stop offset="0%" stopColor="#8B5CF6" />
                    <stop offset="100%" stopColor="#3B82F6" />
                  </linearGradient>
                </defs>
                {[1, 2, 3].map((layer) =>
                  [...Array(8)].map((_, i) => {
                    const angle = (i * 45) * Math.PI / 180;
                    const radius = (layer * 33) / 2;
                    const centerX = 250;
                    const centerY = 250;
                    const x = centerX + radius * Math.cos(angle);
                    const y = centerY + radius * Math.sin(angle);

                    return (
                      <line
                        key={`connection-${layer}-${i}`}
                        x1={centerX}
                        y1={centerY}
                        x2={x}
                        y2={y}
                        stroke="url(#gradient)"
                        strokeWidth="0.5"
                        strokeOpacity="0.3"
                      />
                    );
                  })
                )}
              </svg>

              {[1, 2, 3].map((layer) => (
                <motion.div
                  key={`layer-${layer}`}
                  className="absolute top-1/2 left-1/2 transform -translate-x-1/2 -translate-y-1/2 rounded-full border border-white/10"
                  style={{
                    width: `${layer * 33}%`,
                    height: `${layer * 33}%`,
                  }}
                  animate={{
                    opacity: [0.3, 0.6, 0.3],
                    rotate: 360
                  }}
                  transition={{
                    duration: 20 + layer * 5,
                    repeat: Infinity,
                    ease: "linear"
                  }}
                >
                  {[...Array(8)].map((_, i) => {
                    const angle = (i * 45) * Math.PI / 180;
                    const radius = (layer * 33) / 2;
                    const x = radius * Math.cos(angle);
                    const y = radius * Math.sin(angle);

                    return (
                      <motion.div
                        key={`node-${layer}-${i}`}
                        className="absolute h-4 w-4 rounded-full bg-gradient-to-br from-purple-400 to-blue-300 shadow-lg"
                        style={{
                          left: `calc(50% + ${x}px - 0.5rem)`,
                          top: `calc(50% + ${y}px - 0.5rem)`,
                        }}
                        animate={{
                          scale: [1, 1.3, 1],
                          opacity: [0.7, 1, 0.7]
                        }}
                        transition={{
                          duration: 2 + Math.random(),
                          repeat: Infinity,
                          delay: i * 0.1 + layer * 0.3
                        }}
                      />
                    );
                  })}
                </motion.div>
              ))}

              {/* Pulsing Waves */}
              {[1, 2, 3].map((wave) => (
                <motion.div
                  key={`wave-${wave}`}
                  className="absolute top-1/2 left-1/2 transform -translate-x-1/2 -translate-y-1/2 rounded-full border border-purple-400/20"
                  style={{
                    width: `${wave * 40}%`,
                    height: `${wave * 40}%`,
                  }}
                  animate={{
                    scale: [1, 1.5],
                    opacity: [0.3, 0]
                  }}
                  transition={{
                    duration: 4 + wave,
                    repeat: Infinity,
                    ease: "easeOut"
                  }}
                />
              ))}
            </div>
          </div>
        </motion.div>
      </div>
    </section>
  );
};

export default Hero;
